# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            print("Invalid deposit amount.")
            return False

    def withdraw(self, amount):
        if amount > 0 and amount <= self.balance:
            self.balance -= amount
            return True
        elif amount > self.balance:
            print("Insufficient funds.")
            return False
        else:
            print("Invalid withdrawal amount.")
            return False

    def get_balance(self):
        return self.balance

def process_transaction(account, transaction):
    if transaction[0] == 'deposit':
        account.deposit(transaction[1])
    elif transaction[0] == 'withdraw':
        account.withdraw(transaction[1])
    else:
        print("Invalid transaction type.")

account = Account()
transactions = [('deposit', 100), ('withdraw', 50), ('deposit', 200)]
for transaction in transactions:
    process_transaction(account, transaction)
print(account.get_balance())